import{_ as l,C as a,o as c,c as n,E as e,a3 as h}from"./chunks/framework.CjmLrUhD.js";const p="/ecommerce-ops-vitepress/assets/category-research/image-01.png",d="/ecommerce-ops-vitepress/assets/category-research/image-02.png",m="/ecommerce-ops-vitepress/assets/category-research/image-03.png",g="/ecommerce-ops-vitepress/assets/category-research/image-04.png",_="/ecommerce-ops-vitepress/assets/category-research/image-05.png",u="/ecommerce-ops-vitepress/assets/category-research/image-06.png",b="/ecommerce-ops-vitepress/assets/category-research/image-07.png",q="/ecommerce-ops-vitepress/assets/category-research/image-08.png",T=JSON.parse('{"title":"快速调研类目玩法","description":"通过行业榜单、潜力爆款、竞品监控和关键词数据，快速判断类目机会。","frontmatter":{"title":"快速调研类目玩法","description":"通过行业榜单、潜力爆款、竞品监控和关键词数据，快速判断类目机会。"},"headers":[],"relativePath":"growth/category-research.md","filePath":"growth/category-research.md","lastUpdated":1783647235000}'),y={name:"growth/category-research.md"};function f(P,r,x,k,v,z){const o=a("DocHero"),t=a("ModuleFlow"),s=a("RelatedDocs"),i=a("ImageGallery");return c(),n("div",null,[e(o,{"module-id":"category-research","image-count":10,"section-count":17}),e(t,{"module-id":"category-research"}),e(s,{"module-id":"category-research"}),r[0]||(r[0]=h('<h1 id="快速调研类目玩法执行手册" tabindex="-1">快速调研类目玩法执行手册 <a class="header-anchor" href="#快速调研类目玩法执行手册" aria-label="Permalink to &quot;快速调研类目玩法执行手册&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>类目调研的目标是快速判断机会，而不是写一份很长的市场报告。运营要找到近期增长快的新链接，分析它为什么起来，再判断自己的供应链、价格、素材和运营能力能否复制或超越。</p><h2 id="一、怎么找起来快的新链接" tabindex="-1">一、怎么找起来快的新链接 <a class="header-anchor" href="#一、怎么找起来快的新链接" aria-label="Permalink to &quot;一、怎么找起来快的新链接&quot;">​</a></h2><h3 id="_1-找到行业榜单" tabindex="-1">1. 找到行业榜单 <a class="header-anchor" href="#_1-找到行业榜单" aria-label="Permalink to &quot;1. 找到行业榜单&quot;">​</a></h3><p>先进入行业榜单或平台类目排行，筛选近期增长明显的商品。优先看创建时间短、流量和销量都在递增的链接。老链接长期稳定不一定代表新机会，新链接快速增长更能说明近期需求和打法。</p><p><img src="'+p+'" alt="行业榜单筛选参考" loading="lazy"></p><h3 id="_2-找出增长趋势好的潜力爆款" tabindex="-1">2. 找出增长趋势好的潜力爆款 <a class="header-anchor" href="#_2-找出增长趋势好的潜力爆款" aria-label="Permalink to &quot;2. 找出增长趋势好的潜力爆款&quot;">​</a></h3><p>潜力爆款要同时满足两个条件：增长快，并且增长不是偶然单点爆发。运营需要看最近 7 天、15 天、30 天趋势，判断流量和销量是否持续上升。</p><p><img src="'+d+'" alt="潜力爆款判断参考" loading="lazy"></p><h3 id="_3-分析最近-30-天数据" tabindex="-1">3. 分析最近 30 天数据 <a class="header-anchor" href="#_3-分析最近-30-天数据" aria-label="Permalink to &quot;3. 分析最近 30 天数据&quot;">​</a></h3><p>30 天数据可以帮助判断这个链接是自然起来、付费拉动，还是活动短期爆发。重点看访客、成交、转化、关键词、价格变化和投放痕迹。</p><p><img src="'+m+'" alt="30 天数据分析参考" loading="lazy"></p><h3 id="_4-重点分析关键数据" tabindex="-1">4. 重点分析关键数据 <a class="header-anchor" href="#_4-重点分析关键数据" aria-label="Permalink to &quot;4. 重点分析关键数据&quot;">​</a></h3><p>不要只看销量。销量背后要拆流量来源、成交关键词、付费占比、客单价和转化表现。如果一个链接销量增长主要来自高额付费，而你的预算无法跟进，就不能简单复制。</p><p><img src="'+g+'" alt="重点数据分析参考" loading="lazy"></p><h3 id="_5-监控值得分析的链接" tabindex="-1">5. 监控值得分析的链接 <a class="header-anchor" href="#_5-监控值得分析的链接" aria-label="Permalink to &quot;5. 监控值得分析的链接&quot;">​</a></h3><p>当某个链接符合“创建时间短、流量递增、销量递增、关键词明确”这些条件，就把它加入竞品监控。监控内容包括主图变化、价格变化、标题变化、活动节奏和投放变化。</p><p><img src="'+_+'" alt="竞品监控参考" loading="lazy"></p><h3 id="_6-采集最近-30-天数据" tabindex="-1">6. 采集最近 30 天数据 <a class="header-anchor" href="#_6-采集最近-30-天数据" aria-label="Permalink to &quot;6. 采集最近 30 天数据&quot;">​</a></h3><p>采集时要形成固定字段：链接、店铺、创建时间、价格、销量、访客、成交关键词、付费推广、主图、卖点、评价数。原资料中的视频附件可以作为操作补充，但正文中以表格字段为主。</p><p><strong>附件：采集最近30天数据.mov</strong></p><p><img src="'+u+'" alt="30 天数据采集参考" loading="lazy"></p><h3 id="_7-采集成交关键词" tabindex="-1">7. 采集成交关键词 <a class="header-anchor" href="#_7-采集成交关键词" aria-label="Permalink to &quot;7. 采集成交关键词&quot;">​</a></h3><p>成交关键词是判断需求的核心。运营要识别哪些词带来成交，哪些词只带来流量。成交词可以反推标题、主图卖点、详情页表达和投放关键词。</p><p><strong>附件：快速分析对手的成交关键词.mov</strong></p><p><img src="'+b+'" alt="成交关键词采集参考" loading="lazy"></p><h3 id="_8-采集付费推广数据" tabindex="-1">8. 采集付费推广数据 <a class="header-anchor" href="#_8-采集付费推广数据" aria-label="Permalink to &quot;8. 采集付费推广数据&quot;">​</a></h3><p>付费数据用于判断竞品是否靠预算拉动。若竞品付费强度高，你需要评估自己的预算、素材和承接是否跟得上。若竞品付费不强但增长快，说明自然需求或产品力可能更值得研究。</p><p><strong>附件：付费推广数据采集-字幕版本.mov</strong></p><p><img src="'+q+'" alt="付费推广数据采集参考" loading="lazy"></p><h2 id="输出物模板" tabindex="-1">输出物模板 <a class="header-anchor" href="#输出物模板" aria-label="Permalink to &quot;输出物模板&quot;">​</a></h2><p>每次类目调研至少输出三张表：机会链接表、竞品拆解表、行动建议表。机会链接表记录候选链接；竞品拆解表记录它为什么增长；行动建议表写我们是否跟进、怎么跟进、需要什么资源。</p><p>行动建议不要只写“可以做”。要写清楚：供应链是否具备、价格是否有优势、主图能否做差异、关键词能否覆盖、预算是否能承受、预计先测什么。</p><h2 id="常见误判" tabindex="-1">常见误判 <a class="header-anchor" href="#常见误判" aria-label="Permalink to &quot;常见误判&quot;">​</a></h2><h3 id="只看销量-不看链接年龄" tabindex="-1">只看销量，不看链接年龄 <a class="header-anchor" href="#只看销量-不看链接年龄" aria-label="Permalink to &quot;只看销量，不看链接年龄&quot;">​</a></h3><p>老链接销量高可能只是历史积累，新链接增长快才更能说明近期机会。</p><h3 id="只看自然排名-不看付费痕迹" tabindex="-1">只看自然排名，不看付费痕迹 <a class="header-anchor" href="#只看自然排名-不看付费痕迹" aria-label="Permalink to &quot;只看自然排名，不看付费痕迹&quot;">​</a></h3><p>如果竞品主要靠付费拉动，你需要判断自己是否有同等预算和素材能力。</p><h3 id="看到一个爆款就马上上新" tabindex="-1">看到一个爆款就马上上新 <a class="header-anchor" href="#看到一个爆款就马上上新" aria-label="Permalink to &quot;看到一个爆款就马上上新&quot;">​</a></h3><p>上新前还要判断供应链、毛利、交期、售后风险和平台规则。类目调研只是第一步。</p><h2 id="复盘清单" tabindex="-1">复盘清单 <a class="header-anchor" href="#复盘清单" aria-label="Permalink to &quot;复盘清单&quot;">​</a></h2><ul><li>是否筛选了新链接和增长趋势</li><li>是否采集了 30 天数据</li><li>是否拆出成交关键词</li><li>是否判断付费拉动程度</li><li>是否输出可执行的跟进建议</li></ul>',43)),e(i,{"module-id":"category-research"})])}const w=l(y,[["render",f]]);export{T as __pageData,w as default};
